MAP
 
    NAME cali
    SIZE 1000 1000
    STATUS ON
    EXTENT 1053867 860190 1068491 879441

    FONTSET "misc/fonts/fonts.txt"
    SYMBOLSET "misc/symbols/symbols.sym"

    IMAGECOLOR 233 243 255

    WEB

        IMAGEPATH "c:/ms4w/tmp/ms_tmp/" 
        IMAGEURL "/ms_tmp/"
    END

    LAYER
        NAME "Cali"
        STATUS ON
        DATA "C:\ms4w\Apache\htdocs\Giav-proyecto\Proyecto-accidentabilidad-\Proyecto-Accidentabilidad\web\assets\shapeCali41\CaliArea.shp"  
        TYPE POLYGON
        CLASS
            STYLE
                COLOR 236 238 224
                OUTLINECOLOR 160 160 160
            END
        END
    END

    LAYER
        TRANSPARENCY 70
        NAME "Comunas"
        STATUS ON
        DATA "C:\ms4w\Apache\htdocs\Giav-proyecto\Proyecto-accidentabilidad-\Proyecto-Accidentabilidad\web\assets\shapeCali41\ComunasC.shp" 
        TYPE POLYGON
        CLASS
            STYLE
                COLOR 186 220 255
                OUTLINECOLOR 75 125 185
            END
        END
    END

    LAYER
        TRANSPARENCY 25
        NAME "MallaVial"
        STATUS ON
        DATA "C:\ms4w\Apache\htdocs\Giav-proyecto\Proyecto-accidentabilidad-\Proyecto-Accidentabilidad\web\assets\shapeCali41\MallaVialC.shp" 
        TYPE LINE
        LabelItem "nombre"
        CLASS
            STYLE
                COLOR 120 120 120
                WIDTH 1
            END
            LABEL   
                TYPE TRUETYPE
                FONT "sans"
                ENCODING "UTF-8"
                POSITION CC 
                ANGLE auto
                PARTIALS true
                SIZE 7
                COLOR 80 80 80
                OUTLINECOLOR 255 255 255
                SHADOWCOLOR 255 255 255
                SHADOWSIZE 1 1
            END
        END
    END

    LAYER
        TRANSPARENCY 35
        NAME "Barrio"
        STATUS ON
        DATA "C:\ms4w\Apache\htdocs\Giav-proyecto\Proyecto-accidentabilidad-\Proyecto-Accidentabilidad\web\assets\shapeCali41\Barrios.shp" 
        TYPE POLYGON
        LABELITEM "BARRIO"
        CLASS
            NAME "LABEL"
            STYLE
                COLOR 255 242 204
                OUTLINECOLOR 219 170 0
            END
            LABEL   
                SIZE SMALL
                COLOR 0 0 0
            END
        END
    END
    
    LAYER
        CONNECTIONTYPE postgis
        NAME "Accidentes"
        STATUS ON
        CONNECTION "user=postgres password=12345 dbname=GIAV host=localhost port=5432"
        DATA "coordenadas FROM (SELECT id_reporte_acc, coordenadas FROM reporte_accidente WHERE coordenadas IS NOT NULL) AS acc USING UNIQUE id_reporte_acc USING SRID=4326"
        TYPE POINT
        PROJECTION
            "init=epsg:4326"
        END
        CLASS
            STYLE
                SYMBOL star
                SIZE 18
                COLOR 230 57 70
                OUTLINECOLOR 255 255 255
            END
        END
    END
